import React, { useState, useEffect } from 'react';
import axios from 'axios';
import { Search, Sun, Cloud, CloudRain, Wind, Droplets, Thermometer, CloudLightning, CloudSnow, Eye, Compass, Calendar, Clock } from 'lucide-react';
import './App.css';

const API_KEY = "YOUR_OPENWEATHER_API_KEY_HERE"; 

function App() {
  const [city, setCity] = useState('Visnagar');
  const [weatherData, setWeatherData] = useState(null);
  const [forecastData, setForecastData] = useState([]);
  const [hourlyData, setHourlyData] = useState([]);
  const [aqi, setAqi] = useState(null);
  const [loading, setLoading] = useState(false);
  const [error, setError] = useState('');
  const [currentTime, setCurrentTime] = useState('');

  const fetchWeather = async (searchCity) => {
    setLoading(true);
    setError('');
    try {
      // Current Weather
      const currentRes = await axios.get(
        `https://api.openweathermap.org/data/2.5/weather?q=${searchCity}&units=metric&appid=${API_KEY}`
      );
      setWeatherData(currentRes.data);

      const { lat, lon } = currentRes.data.coord;

      // Air Quality
      const aqiRes = await axios.get(
        `https://api.openweathermap.org/data/2.5/air_pollution?lat=${lat}&lon=${lon}&appid=${API_KEY}`
      );
      setAqi(aqiRes.data.list[0].main.aqi);

      // Forecast Data
      const forecastRes = await axios.get(
        `https://api.openweathermap.org/data/2.5/forecast?q=${searchCity}&units=metric&appid=${API_KEY}`
      );

      setHourlyData(forecastRes.data.list.slice(0, 6)); // Next 18 Hours
      const dailyData = forecastRes.data.list.filter(item => item.dt_txt.includes("12:00:00"));
      setForecastData(dailyData);

    } catch (err) {
      setError('શહેરનું નામ ખોટું છે અથવા નેટવર્ક પ્રોબ્લેમ છે.');
    } finally {
      setLoading(false);
    }
  };

  useEffect(() => {
    fetchWeather(city);
    // લાઈવ ટાઈમ અપડેટ માટે
    const timer = setInterval(() => {
      const now = new Date();
      setCurrentTime(now.toLocaleTimeString('en-US', { hour: '2-digit', minute: '2-digit' }));
    }, 1000);
    return () => clearInterval(timer);
  }, []);

  const handleSearch = (e) => {
    e.preventDefault();
    if (city.trim()) fetchWeather(city);
  };

  const getWeatherIcon = (main, size = 40) => {
    switch (main) {
      case 'Clear': return <Sun className="vibe-icon text-amber" size={size} />;
      case 'Clouds': return <Cloud className="vibe-icon text-slate" size={size} />;
      case 'Rain': case 'Drizzle': return <CloudRain className="vibe-icon text-cyan" size={size} />;
      case 'Thunderstorm': return <CloudLightning className="vibe-icon text-purple" size={size} />;
      case 'Snow': return <CloudSnow className="vibe-icon text-blue" size={size} />;
      default: return <Sun className="vibe-icon text-amber" size={size} />;
    }
  };

  const getAQIStatus = (index) => {
    const status = {
      1: { text: 'ઉત્તમ (Good)', pct: 20, color: '#10b981' },
      2: { text: 'સાધારણ (Fair)', pct: 40, color: '#a855f7' },
      3: { text: 'મધ્યમ (Moderate)', pct: 60, color: '#f59e0b' },
      4: { text: 'ખરાબ (Poor)', pct: 80, color: '#f87171' },
      5: { text: 'ગંભીર (Severe)', pct: 100, color: '#ef4444' }
    };
    return status[index] || { text: '--', pct: 0, color: '#fff' };
  };

  return (
    <div className="pro-dashboard">

      {/* SIDEBAR NAVIGATION CONTROL */}
      <aside className="sidebar">
        <div className="logo-section">
          <Compass size={28} className="logo-icon" />
          <h2>Sky<span>Analytics</span></h2>
        </div>
        <form onSubmit={handleSearch} className="premium-search">
          <input 
            type="text" 
            placeholder="શહેર સર્ચ કરો..." 
            value={city}
            onChange={(e) => setCity(e.target.value)}
          />
          <button type="submit"><Search size={16} /></button>
        </form>
        <div className="nav-info">
          <div className="time-widget">
            <Clock size={16} /> <span>{currentTime || 'Loading...'}</span>
          </div>
          <div className="time-widget">
            <Calendar size={16} /> <span>{new Date().toLocaleDateString('gu-IN', { day: 'numeric', month: 'short' })}</span>
          </div>
        </div>
      </aside>

      {/* MAIN CONTENT WORKSPACE */}
      <main className="main-workspace">
        {loading && <div className="loader-screen"><div className="spinner"></div><p>સેટેલાઇટ કનેક્ટ થઈ રહ્યો છે...</p></div>}
        {error && <div className="error-screen">{error}</div>}

        {weatherData && !loading && !error && (
          <div className="workspace-grid">

            {/* HERO BANNER SECTION */}
            <section className="hero-banner-card">
              <div className="hero-left">
                <span className="badge">LIVE ATMOSPHERE</span>
                <h1 className="hero-city">{weatherData.name}</h1>
                <p className="hero-desc">{weatherData.weather[0].description}</p>
                <div className="hero-temp-group">
                  <h2>{Math.round(weatherData.main.temp)}°</h2>
                  <span className="unit">Celsius</span>
                </div>
              </div>
              <div className="hero-right">
                {getWeatherIcon(weatherData.weather[0].main, 160)}
              </div>
            </section>

            {/* HOURLY TIMELINE SECTION */}
            <section className="hourly-timeline-card">
              <h3><Clock size={16} /> હોરલી ટાઈમલાઈન (આગામી કલાકો)</h3>
              <div className="timeline-scroller">
                {hourlyData.map((hour, idx) => (
                  <div key={idx} className="timeline-node">
                    <span className="time">{hour.dt_txt.split(' ')[1].substring(0, 5)}</span>
                    <div className="node-icon-bg">{getWeatherIcon(hour.weather[0].main, 24)}</div>
                    <span className="temp">{Math.round(hour.main.temp)}°C</span>
                  </div>
                ))}
              </div>
            </section>

            {/* ANALYTICS METRICS MATRIX */}
            <section className="metrics-matrix">
              <div className="metric-card">
                <div className="m-head"><Thermometer size={16} /> <span>Feels Like</span></div>
                <h4>{Math.round(weatherData.main.feels_like)}°C</h4>
              </div>
              <div className="metric-card">
                <div className="m-head"><Droplets size={16} /> <span>Humidity</span></div>
                <h4>{weatherData.main.humidity}%</h4>
              </div>
              <div className="metric-card">
                <div className="m-head"><Wind size={16} /> <span>Wind Speed</span></div>
                <h4>{weatherData.wind.speed} <span className="sub">m/s</span></h4>
              </div>
              <div className="metric-card">
                <div className="m-head"><Eye size={16} /> <span>Visibility</span></div>
                <h4>{(weatherData.visibility / 1000).toFixed(1)} <span className="sub">km</span></h4>
              </div>

              {/* AIR QUALITY INSIGHT INDEX */}
              <div className="metric-card aqi-fullspan">
                <div className="m-head"><span>Air Quality Index (AQI)</span></div>
                <div className="aqi-progress-container">
                  <div className="aqi-info-row">
                    <span className="aqi-status-text" style={{ color: getAQIStatus(aqi).color }}>
                      {getAQIStatus(aqi).text}
                    </span>
                    <span className="aqi-val">Level {aqi}/5</span>
                  </div>
                  <div className="progress-bar-bg">
                    <div className="progress-bar-fill" style={{ width: `${getAQIStatus(aqi).pct}%`, backgroundColor: getAQIStatus(aqi).color }}></div>
                  </div>
                </div>
              </div>
            </section>

            {/* WEEKLY OUTLOOK PANEL */}
            <section className="weekly-outlook-card">
              <h3><Calendar size={16} /> 5-દિવસીય વિસ્તૃત આગાહી</h3>
              <div className="weekly-list">
                {forecastData.map((day, idx) => (
                  <div key={idx} className="weekly-row">
                    <span className="w-day">{new Date(day.dt * 1000).toLocaleDateString('gu-IN', { weekday: 'long' })}</span>
                    <div className="w-status">
                      {getWeatherIcon(day.weather[0].main, 22)}
                      <span className="w-condition">{day.weather[0].main}</span>
                    </div>
                    <span className="w-temp">{Math.round(day.main.temp)}°C</span>
                  </div>
                ))}
              </div>
            </section>

          </div>
        )}
      </main>
    </div>
  );
}

export default App;
